		-- If DropFracBits_c < 1, then NeedRound_c = FALSE, so the value is never used (just return 0).
		if DropFracBits_c <= 1 then
			return "0";
		end if;
		-- If DropFracBits_c > 1 then 2**(DropFracBits_c-1)-1 = "11...1"
		return (DropFracBits_c-2 downto 0 => '1');
	end function;

